using NP std;
NP phigrOS
{
    il ll read()
    {
        ll x=0,f=1;char ch=gc();
        wh(ch<'0'||ch>'9'){if(ch=='-')f=-1;ch=getchar();}
        wh(ch>='0'&&ch<='9'){x=x*10+ch-'0';ch=gc();}
        return x*f;
    }
    void write(ll x)
    {
        if(x<0)pc('-'),x=-x;
        if(x>9)write(x/10);
        pc(x%10+'0');
    }
    void writeln(ll x)
    {
        write(x);
        puts("");
        return;
    }
}
using NP phigrOS;
CI MAXN=1e5+5;
int n,m;
int p[MAXN],c[MAXN];
vector<int> cs[MAXN];
int cnt[MAXN];
int solve(int x)
{
	int cur=cnt[1],res=0;
	vector <int> tmp;
	FOR(i,2,n)
	{

		int s=cs[i].size()-(x-1); 
		int k=max(s,0LL);
		FOR(j,0,k-1)res+=cs[i][j];
		cur+=k;
        int css=cs[i].size();
		FOR(j,k,css-1)tmp.pb(cs[i][j]);
	}
	sort(tmp.begin(),tmp.end());
	if(cur<x)
	{
		FOR(i,0,x-cur-1)res+=tmp[i]; 
	}
	return res;
}
signed main()
{
	n=read(),m=read();
	FOR(i,1,m)
	{
		cin>>p[i]>>c[i];
		++cnt[p[i]];
		cs[p[i]].push_back(c[i]);
	}
	FOR(i,1,n)sort(cs[i].begin(),cs[i].end());
	int ans=1e18;
	FOR(i,1,m)ans=min(ans,solve(i));
    write(ans);
	return false;
}
